export default function LeavePage() {
  const { user } = useAuth();
  const posId = parseInt(user?.PositionID || user?.positionId, 10);
  const roleStr = (user?.role || user?.Role || '').toUpperCase();

  const isHRManager = posId === 1;
  const isSupervisor = posId === 2 || roleStr.includes('PROFESSOR') || roleStr.includes('MANAGER');
  const isBasicHR = (roleStr.includes('HR') || roleStr.includes('ADMIN')) && !isHRManager;

  const isManagement = isHRManager || isSupervisor || isBasicHR;
  const canDelegate = isHRManager || isSupervisor;

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);
  const [holidays, setHolidays] = useState([]);
  const [loadBal, setLoadBal] = useState(true);
  const [loadAll, setLoadAll] = useState(true);
  const [overrideReq, setOverrideReq] = useState(null);
  const [showAdjustmentModal, setShowAdjustmentModal] = useState(false);

  const loadData = useCallback(() => {
    setLoadBal(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r)));
    leaveAPI.getTypes().then(r => setTypes(toArr(r)));
    if (isHRManager && leaveAPI.listHolidays) leaveAPI.listHolidays().then(r => setHolidays(toArr(r)));

    if (isManagement) {
      setLoadAll(true);
      const fetchMethod = isHRManager || isBasicHR ? leaveAPI.listAll() : leaveAPI.getManagerInbox();
      fetchMethod.then(r => setAll(toArr(r))).finally(() => setLoadAll(false));
    }
  }, [isHRManager, isSupervisor, isBasicHR, isManagement]);

  useEffect(() => { loadData(); }, [loadData]);

  const uniqueEmployees = Array.from(new Map(allRequests.filter(r => r.EmployeeID || r.employeeId).map(r => [r.EmployeeID || r.employeeId, r.Employee?.FullName || r.employeeName])).entries()).map(([id, name]) => ({ id, name }));

  const handleAction = async (id, action) => {
    try {
      if (action === 'approve') await leaveAPI.approveReject(id, { decision: 'APPROVED' });
      else if (action === 'reject') await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: 'Rejected' });
      else if (action === 'cancel') await leaveAPI.cancel(id, { CancelReason: 'User Cancelled' });
      toast.success('Done'); loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
  };

  const handlePayrollSync = () => leaveAPI.syncPayroll({}).then(() => toast.success("Payroll Synced"));

  return (
    <>
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Control your requests and configurations</p></div>
        <button className="btn btn-primary" onClick={() => toast.error("Form logic placeholder")}>New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        <button className={`tab-btn ${tab === 'dashboard' ? 'active' : ''}`} onClick={() => setTab('dashboard')}>Dashboard</button>
        <button className={`tab-btn ${tab === 'history' ? 'active' : ''}`} onClick={() => setTab('history')}>My History</button>
        {isManagement && <button className={`tab-btn ${tab === 'all' ? 'active' : ''}`} onClick={() => setTab('all')}>{isHRManager || isBasicHR ? 'Company Data' : 'Team Inbox'}</button>}
        {isHRManager && <button className={`tab-btn ${tab === 'settings' ? 'active' : ''}`} onClick={() => setTab('settings')}>Settings</button>}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && <div className="grid-4">{balances.map((b, i) => <BalanceCard key={i} balance={b} loading={loadBal} />)}</div>}

        {tab === 'all' && isManagement && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {canDelegate && <DelegationPanel onDelegate={(id, p) => leaveAPI.delegate(id, p)} employees={uniqueEmployees} />}
            <div className="card">
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th></tr></thead>
                  <tbody>{allRequests.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onOverrideClick={setOverrideReq} isSupervisor={isSupervisor} isHRManager={isHRManager} isBasicHR={isBasicHR} />)}</tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {tab === 'settings' && isHRManager && (
          <div className="settings-grid">
            <LeaveTypeManager types={leaveTypes} onAdd={d => leaveAPI.createType(d).then(loadData)} />
            <HolidayManager holidays={holidays} onAdd={d => leaveAPI.createHoliday(d).then(loadData)} />
            <div className="card p-4 mt-4">
              <div className="card-title"><ArrowRightLeft size={16}/> Integration</div>
              <div className="d-flex gap-3 mt-3">
                <button className="btn btn-outline-primary" onClick={handlePayrollSync}>Sync Payroll</button>
                <button className="btn btn-outline-danger" onClick={() => setShowAdjustmentModal(true)}>Adjust Balance</button>
              </div>
            </div>
          </div>
        )}
      </div>

      {overrideReq && isHRManager && (
        <InlineModal title="HR Manager Override" onClose={() => setOverrideReq(null)}>
          <p>Manual decision for {overrideReq.Employee?.FullName}</p>
          <div className="d-flex gap-2 mt-4">
            <button className="btn btn-success" onClick={() => { handleAction(overrideReq.id, 'approve'); setOverrideReq(null); }}>Approve</button>
            <button className="btn btn-danger" onClick={() => { handleAction(overrideReq.id, 'reject'); setOverrideReq(null); }}>Reject</button>
          </div>
        </InlineModal>
      )}
    </>
  );
}
